VALUES
  ('pukao-e3452428-moex-00535', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於行政處分之撤銷，下列敘述何者錯誤？', '["桃園市政府環境保護局稽查人員至新竹市出差時，對任意棄置廢棄物之民眾作成裁罰處分，該處分無須 撤銷", "主管機關未給予相對人陳述意見之機會，即作成裁罰處分時，該處分為得撤銷", "教育部核可申請人升等為副教授，卻未發給副教授證書，該升等處分為得撤銷", "工廠未檢具事業廢棄物清理計畫書，直轄市政府即許可其營業，該許可處分為得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00536', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於行政處分之敘述，下列何者錯誤？', '["行政處分之作成違法者，該處分即屬無效", "合法行政處分，包括形式上合法及實質上合法", "行政處分屬於行政機關之單方行政行為，不因其用語、形式而有異", "指行政機關就公法上具體事件所為之決定，對外直接發生法律效果之單方行政行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00537', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["行政契約發生債務不履行時，行政機關得自為行政處分", "契約內容須不牴觸法律", "須締約之機關有權限", "須依法定方式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00538', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '衛生福利部中央健康保險署與醫事服務機構締結之全民健康保險特約之性質為何？', '["需相對人同意之行政處分", "私法契約", "行政契約", "行政指導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00539', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '下列行為何者非屬行政事實行為？', '["警察巡邏", "警察追捕逃犯", "警察於巡邏箱簽名", "警察於路口指揮交通"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00540', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '依行政罰法，關於物之扣留，下列敘述何者正確？', '["扣留之對象，限於得沒入之物，並以供檢查、檢驗、鑑定或保全為扣留目的", "應扣留物不便搬運或保管者，仍得扣留，並得命人看守或交由所有人或其他適當之人保管", "易生危險之扣留物，不得毀棄之", "受處罰者對扣留聲明異議後，對於異議決定仍有不服，原則上得單獨對扣留逕行提起行政訴訟，請求返還"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00541', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '乙為甲公司之董事長，丙為甲公司之職員，丙執行職務之故意行為致使甲公司應受行政處罰者，下列敘述 何者正確？', '["丙應並受同一規定罰鍰之處罰", "丙之故意得推定為乙未盡其防止義務之故意", "乙如因故意而未盡其防止義務，乙丙即為故意共同實施違反行政法上義務之行為者", "乙如因過失而未盡其防止義務時，不並受同一規定罰鍰之處罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00542', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["一行為同時觸犯刑事法及違反行政法上義務者，依刑事法處罰", "一行為同時觸犯刑事法及違反行政法上義務，刑事部分獲無罪確定者，不得再以違反行政法上義務之規 定裁處之", "一行為違反社會秩序維護法及其他行政法上義務者而應受處罰時，如已裁處拘留者，不得再處以罰鍰", "一行為違反數個行政法上義務而應處罰鍰者，依法定罰鍰額最高之規定裁處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00543', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '關於行政罰裁處權時效之敘述，下列何者錯誤？', '["行政罰之裁處權，因2年期間之經過而消滅", "裁處權時效，因天災、事變或依法律規定不能開始或進行裁處時，停止其進行", "行政罰之裁處權期間，原則上自違反行政法上義務之行為終了時起算", "行政罰之裁處因訴願等經撤銷而須另為裁處者，裁處權期間自原裁處被撤銷確定之日起算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00544', 'pukao-e3452428', 'pukao-e3452428-moex-111-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '下列何者非行政執行機關當然應依職權停止行政執行程序之法定事由？', '["行政執行義務人之義務已全部履行", "行政執行所憑之執行名義行政處分，經原處分機關之上級機關予以撤銷", "行政執行義務人應履行之義務經證明為不可能", "債務人主張對其所採取之查封手段過於嚴苛，聲明異議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
